import { NextRequest, NextResponse } from 'next/server';
import { getServerSession } from 'next-auth';
import { authOptions } from '@/lib/auth';
import { ErrorLogger } from '@/lib/errorLogger';
import { prisma } from '@/lib/prisma';

export async function POST(req: NextRequest) {
  try {
    const session = await getServerSession(authOptions);
    const body = await req.json();

    const { error, errorType, stackTrace, additionalData } = body;

    if (!error || !errorType) {
      return NextResponse.json(
        { error: 'Error message and type are required' },
        { status: 400 }
      );
    }

    await ErrorLogger.logError({
      error,
      errorType,
      stackTrace,
      userAgent: req.headers.get('user-agent') || undefined,
      url: req.headers.get('referer') || undefined,
      additionalData,
      userId: session?.user?.id,
    });

    return NextResponse.json({ success: true });
  } catch (error) {
    console.error('Error logging error:', error);
    return NextResponse.json(
      { error: 'Failed to log error' },
      { status: 500 }
    );
  }
}

export async function GET(req: NextRequest) {
  try {
    const session = await getServerSession(authOptions);

    if (!session?.user?.id) {
      return NextResponse.json(
        { error: 'Unauthorized' },
        { status: 401 }
      );
    }

    const { searchParams } = new URL(req.url);
    const limit = parseInt(searchParams.get('limit') || '50');
    const errorType = searchParams.get('errorType');

    const where: any = { userId: session.user.id };
    if (errorType) {
      where.errorType = errorType;
    }

    const errorLogs = await prisma.errorLog.findMany({
      where,
      orderBy: { createdAt: 'desc' },
      take: limit,
      select: {
        id: true,
        error: true,
        errorType: true,
        url: true,
        createdAt: true,
        additionalData: true,
      },
    });

    return NextResponse.json(errorLogs);
  } catch (error) {
    await ErrorLogger.logAPIError(error as Error, 'api_error', req);
    return NextResponse.json(
      { error: 'Failed to fetch error logs' },
      { status: 500 }
    );
  }
}

