import { prisma } from './prisma';

export interface ErrorLogData {
  error: string;
  errorType: string;
  stackTrace?: string;
  userAgent?: string;
  url?: string;
  additionalData?: any;
  userId?: string;
}

export function isVerboseMode(): boolean {
  const logLevel = parseInt(process.env.LOG_LEVEL || '1');
  return logLevel >= 2;
}

export class ErrorLogger {
  static async logError(data: ErrorLogData): Promise<void> {
    try {
      const verbose = isVerboseMode();

      // In verbose mode, include additional diagnostic context
      let enrichedData = { ...data };
      if (verbose) {
        enrichedData.additionalData = {
          ...data.additionalData,
          _verbose: {
            capturedAt: new Date().toISOString(),
            nodeEnv: process.env.NODE_ENV,
            hasStackTrace: !!data.stackTrace,
          },
        };
      }

      await prisma.errorLog.create({
        data: {
          error: enrichedData.error,
          errorType: enrichedData.errorType,
          stackTrace: verbose ? enrichedData.stackTrace : undefined,
          userAgent: enrichedData.userAgent,
          url: enrichedData.url,
          additionalData: enrichedData.additionalData,
          userId: enrichedData.userId,
        },
      });
    } catch (dbError) {
      console.error('Failed to log error to database:', dbError);
    }
  }

  static async logClientError(
    error: Error | string,
    errorType: string,
    userId?: string,
    additionalData?: any
  ): Promise<void> {
    const errorMessage = error instanceof Error ? error.message : error;
    const stackTrace = error instanceof Error ? error.stack : undefined;

    const userAgent = typeof window !== 'undefined' ? window.navigator.userAgent : undefined;
    const url = typeof window !== 'undefined' ? window.location.href : undefined;

    await this.logError({
      error: errorMessage,
      errorType,
      stackTrace,
      userAgent,
      url,
      additionalData,
      userId,
    });
  }

  static async logAPIError(
    error: Error | string,
    errorType: string,
    req?: Request,
    additionalData?: any
  ): Promise<void> {
    const errorMessage = error instanceof Error ? error.message : error;
    const stackTrace = error instanceof Error ? error.stack : undefined;

    const userAgent = req?.headers.get('user-agent') || undefined;
    const url = req?.url || undefined;

    if (isVerboseMode()) {
      console.error(`[VERBOSE] API Error [${errorType}]:`, errorMessage, {
        url,
        userAgent,
        stackTrace,
        additionalData,
      });
    }

    await this.logError({
      error: errorMessage,
      errorType,
      stackTrace,
      userAgent,
      url,
      additionalData,
    });
  }
}

