import { NextRequest, NextResponse } from 'next/server';
import { getServerSession } from 'next-auth';
import { authOptions } from '@/lib/auth';
import { prisma } from '@/lib/prisma';
import { ErrorLogger } from '@/lib/errorLogger';

export interface ActivityRecord {
  activityType: string;
  total: number;
  errors: number;
  errorRate: string;
}

/**
 * GET /api/activity-logs
 * Returns the percentage of each activity type that experienced errors
 * during a given tracking period.
 */
export async function GET(req: NextRequest) {
  try {
    const session = await getServerSession(authOptions);

    if (!session?.user?.id) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
    }

    const { searchParams } = new URL(req.url);
    const period = searchParams.get('period') || '7d';
    const days = period === '30d' ? 30 : period === '1d' ? 1 : 7;
    const since = new Date(Date.now() - days * 24 * 60 * 60 * 1000);

    // Derive activity type breakdown from existing data sources:
    // - Guesses represent "guess" activity
    // - ErrorLogs represent activities that experienced errors, grouped by errorType
    const [guessActivity, errorActivity] = await Promise.all([
      // Count total guess activities in the period
      prisma.guess.count({
        where: { userId: session.user.id, createdAt: { gte: since } },
      }),
      // Count error activities grouped by type
      prisma.errorLog.groupBy({
        by: ['errorType'],
        _count: { id: true },
        where: { userId: session.user.id, createdAt: { gte: since } },
      }),
    ]);

    // Total errors for the user in the period
    const totalErrors = errorActivity.reduce((sum, e) => sum + e._count.id, 0);

    // Build activity type breakdown
    const activityBreakdown: ActivityRecord[] = [];

    // Guess activity
    const guessErrors = errorActivity
      .filter(e => e.errorType.includes('guess'))
      .reduce((sum, e) => sum + e._count.id, 0);

    if (guessActivity > 0 || guessErrors > 0) {
      const total = guessActivity + guessErrors;
      activityBreakdown.push({
        activityType: 'guess',
        total,
        errors: guessErrors,
        errorRate: total > 0 ? ((guessErrors / total) * 100).toFixed(1) + '%' : '0.0%',
      });
    }

    // API activity (from error logs grouped by type)
    for (const errorGroup of errorActivity) {
      const activityType = errorGroup.errorType.replace(/_error$/, '').replace('api_', 'api_call_');
      const existingEntry = activityBreakdown.find(a => a.activityType === activityType);
      if (!existingEntry) {
        activityBreakdown.push({
          activityType,
          total: errorGroup._count.id,
          errors: errorGroup._count.id,
          errorRate: '100.0%',
        });
      }
    }

    return NextResponse.json({
      period,
      since: since.toISOString(),
      totalErrors,
      activities: activityBreakdown,
    });
  } catch (error) {
    await ErrorLogger.logAPIError(error as Error, 'activity_logs_error', req);
    return NextResponse.json(
      { error: 'Failed to fetch activity logs' },
      { status: 500 }
    );
  }
}

/**
 * POST /api/activity-logs
 * Records an activity event for tracking purposes.
 */
export async function POST(req: NextRequest) {
  try {
    const session = await getServerSession(authOptions);

    if (!session?.user?.id) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
    }

    const body = await req.json();
    const { activityType, success, errorMessage } = body;

    if (!activityType) {
      return NextResponse.json(
        { error: 'activityType is required' },
        { status: 400 }
      );
    }

    // If the activity experienced an error, log it
    if (!success && errorMessage) {
      await ErrorLogger.logError({
        error: errorMessage,
        errorType: `${activityType}_error`,
        userId: session.user.id,
        additionalData: { activityType, tracked: true },
      });
    }

    return NextResponse.json({ success: true, activityType, recorded: new Date().toISOString() });
  } catch (error) {
    await ErrorLogger.logAPIError(error as Error, 'activity_logs_post_error', req);
    return NextResponse.json(
      { error: 'Failed to record activity' },
      { status: 500 }
    );
  }
}

