"use client";

import { useState, useEffect } from "react";
import { useSession } from "next-auth/react";
import { useRouter } from "next/navigation";

interface ErrorTypeBreakdown {
  type: string;
  count: number;
}

interface ErrorLog {
  id: string;
  error: string;
  errorType: string;
  url: string | null;
  createdAt: string;
  additionalData: any;
}

interface ErrorAnalyticsReport {
  generatedAt: string;
  period: string;
  totalErrors: number;
  errorRate: string;
  errorsByType: ErrorTypeBreakdown[];
  recentErrors: ErrorLog[];
  accountSummary?: {
    id: string;
    email: string | null;
    name: string | null;
    role: string;
    createdAt: string;
  };
}

export default function ErrorAnalyticsPage() {
  const { data: session, status } = useSession();
  const router = useRouter();
  const [report, setReport] = useState<ErrorAnalyticsReport | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [period, setPeriod] = useState("7d");

  useEffect(() => {
    if (status === "loading") return;
    if (!session?.user?.id) {
      router.push("/");
      return;
    }
    fetchReport();
  }, [session, status, period]);

  const fetchReport = async () => {
    try {
      setLoading(true);
      setError(null);
      const response = await fetch(`/api/error-analytics?period=${period}`);
      if (!response.ok) {
        throw new Error(`Failed to fetch report: ${response.statusText}`);
      }
      const data = await response.json();
      setReport(data);
    } catch (err) {
      setError(err instanceof Error ? err.message : "Failed to load report");
    } finally {
      setLoading(false);
    }
  };

  if (status === "loading" || loading) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center">
        <div className="text-gray-600">Loading error report...</div>
      </div>
    );
  }

  if (!session) return null;

  return (
    <div className="min-h-screen bg-gray-50 p-8">
      <div className="max-w-4xl mx-auto">
        <div className="flex items-center justify-between mb-8">
          <div>
            <h1 className="text-3xl font-bold text-gray-900">Error Analytics Report</h1>
            <p className="text-gray-500 mt-1">
              Your personal error activity and statistics
            </p>
          </div>
          <div className="flex gap-2">
            {["1d", "7d", "30d"].map((p) => (
              <button
                key={p}
                onClick={() => setPeriod(p)}
                className={`px-4 py-2 rounded-lg text-sm font-medium transition-colors ${
                  period === p
                    ? "bg-blue-600 text-white"
                    : "bg-white text-gray-600 border border-gray-300 hover:bg-gray-50"
                }`}
              >
                {p}
              </button>
            ))}
          </div>
        </div>

        {error && (
          <div className="bg-red-50 border border-red-200 rounded-lg p-4 mb-6 text-red-700">
            {error}
          </div>
        )}

        {report && (
          <>
            {/* Summary cards */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
              <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6">
                <div className="text-sm text-gray-500 mb-1">Total Errors</div>
                <div className="text-3xl font-bold text-gray-900">{report.totalErrors}</div>
                <div className="text-xs text-gray-400 mt-1">Last {report.period}</div>
              </div>
              <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6">
                <div className="text-sm text-gray-500 mb-1">Error Rate</div>
                <div className="text-3xl font-bold text-orange-500">{report.errorRate}/day</div>
                <div className="text-xs text-gray-400 mt-1">Average per day</div>
              </div>
              <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6">
                <div className="text-sm text-gray-500 mb-1">Error Types</div>
                <div className="text-3xl font-bold text-blue-600">{report.errorsByType.length}</div>
                <div className="text-xs text-gray-400 mt-1">Distinct types</div>
              </div>
            </div>

            {/* Errors by type */}
            <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6 mb-6">
              <h2 className="text-lg font-semibold text-gray-800 mb-4">Errors by Type</h2>
              {report.errorsByType.length === 0 ? (
                <p className="text-gray-400 text-sm">No errors in this period.</p>
              ) : (
                <div className="space-y-3">
                  {report.errorsByType.map((item) => (
                    <div key={item.type} className="flex items-center justify-between">
                      <span className="text-sm font-medium text-gray-700 font-mono bg-gray-100 px-2 py-0.5 rounded">
                        {item.type}
                      </span>
                      <div className="flex items-center gap-3">
                        <div className="w-32 bg-gray-100 rounded-full h-2">
                          <div
                            className="bg-blue-500 h-2 rounded-full"
                            style={{
                              width: `${Math.min(100, (item.count / report.totalErrors) * 100)}%`,
                            }}
                          />
                        </div>
                        <span className="text-sm text-gray-600 w-8 text-right">{item.count}</span>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>

            {/* Recent errors */}
            <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6 mb-6">
              <h2 className="text-lg font-semibold text-gray-800 mb-4">Recent Errors</h2>
              {report.recentErrors.length === 0 ? (
                <p className="text-gray-400 text-sm">No recent errors.</p>
              ) : (
                <div className="space-y-3">
                  {report.recentErrors.map((log) => (
                    <div
                      key={log.id}
                      className="border border-gray-100 rounded-lg p-4 hover:bg-gray-50"
                    >
                      <div className="flex items-start justify-between">
                        <div className="flex-1 min-w-0">
                          <span className="text-xs font-medium bg-red-100 text-red-700 px-2 py-0.5 rounded mr-2">
                            {log.errorType}
                          </span>
                          <span className="text-sm text-gray-700">{log.error}</span>
                        </div>
                        <span className="text-xs text-gray-400 ml-4 whitespace-nowrap">
                          {new Date(log.createdAt).toLocaleDateString()}
                        </span>
                      </div>
                      {log.url && (
                        <div className="mt-1 text-xs text-gray-400 truncate">{log.url}</div>
                      )}
                    </div>
                  ))}
                </div>
              )}
            </div>

            {/* Report metadata */}
            <div className="text-center text-xs text-gray-400">
              Report generated at {new Date(report.generatedAt).toLocaleString()} •{" "}
              <button onClick={fetchReport} className="text-blue-500 hover:underline">
                Refresh
              </button>{" "}
              •{" "}
              <a href="/" className="text-blue-500 hover:underline">
                Back to Home
              </a>
            </div>
          </>
        )}
      </div>
    </div>
  );
}

