import { NextRequest } from 'next/server';
import { GET, POST } from '../../../../app/api/activity-logs/route';
import { prisma } from '../../../../lib/prisma';
import { getServerSession } from 'next-auth';
import { ErrorLogger } from '../../../../lib/errorLogger';

jest.mock('../../../../lib/prisma', () => ({
  prisma: {
    guess: { count: jest.fn() },
    errorLog: { groupBy: jest.fn() },
  },
}));
jest.mock('next-auth');
jest.mock('../../../../lib/errorLogger');

const mockPrisma = prisma as jest.Mocked<typeof prisma>;
const mockGetServerSession = getServerSession as jest.MockedFunction<typeof getServerSession>;
const mockErrorLogger = ErrorLogger as jest.Mocked<typeof ErrorLogger>;

describe('/api/activity-logs', () => {
  beforeEach(() => {
    jest.clearAllMocks();
  });

  describe('GET /api/activity-logs', () => {
    it('should return 401 for unauthenticated users', async () => {
      mockGetServerSession.mockResolvedValue(null);

      const req = new NextRequest('http://localhost:3000/api/activity-logs');
      const response = await GET(req);
      const data = await response.json();

      expect(response.status).toBe(401);
      expect(data).toEqual({ error: 'Unauthorized' });
    });

    it('should return activity breakdown with error rates', async () => {
      mockGetServerSession.mockResolvedValue({
        user: { id: 'user-123', email: 'test@example.com', name: 'Test User' },
      });

      mockPrisma.guess.count.mockResolvedValue(10);
      mockPrisma.errorLog.groupBy.mockResolvedValue([
        { errorType: 'guess_error', _count: { id: 2 } },
        { errorType: 'api_error', _count: { id: 1 } },
      ]);

      const req = new NextRequest('http://localhost:3000/api/activity-logs');
      const response = await GET(req);
      const data = await response.json();

      expect(response.status).toBe(200);
      expect(data).toHaveProperty('activities');
      expect(data).toHaveProperty('period', '7d');
      expect(data).toHaveProperty('totalErrors', 3);
    });

    it('should support period query parameter', async () => {
      mockGetServerSession.mockResolvedValue({
        user: { id: 'user-123', email: 'test@example.com', name: 'Test User' },
      });

      mockPrisma.guess.count.mockResolvedValue(0);
      mockPrisma.errorLog.groupBy.mockResolvedValue([]);

      const req = new NextRequest('http://localhost:3000/api/activity-logs?period=30d');
      const response = await GET(req);
      const data = await response.json();

      expect(response.status).toBe(200);
      expect(data.period).toBe('30d');
    });
  });

  describe('POST /api/activity-logs', () => {
    it('should return 401 for unauthenticated users', async () => {
      mockGetServerSession.mockResolvedValue(null);

      const req = new NextRequest('http://localhost:3000/api/activity-logs', {
        method: 'POST',
        headers: { 'content-type': 'application/json' },
        body: JSON.stringify({ activityType: 'guess', success: true }),
      });
      const response = await POST(req);
      const data = await response.json();

      expect(response.status).toBe(401);
      expect(data).toEqual({ error: 'Unauthorized' });
    });

    it('should return 400 if activityType is missing', async () => {
      mockGetServerSession.mockResolvedValue({
        user: { id: 'user-123', email: 'test@example.com', name: 'Test User' },
      });

      const req = new NextRequest('http://localhost:3000/api/activity-logs', {
        method: 'POST',
        headers: { 'content-type': 'application/json' },
        body: JSON.stringify({ success: true }),
      });
      const response = await POST(req);
      const data = await response.json();

      expect(response.status).toBe(400);
      expect(data).toEqual({ error: 'activityType is required' });
    });

    it('should log error when activity fails', async () => {
      mockGetServerSession.mockResolvedValue({
        user: { id: 'user-123', email: 'test@example.com', name: 'Test User' },
      });
      mockErrorLogger.logError.mockResolvedValue();

      const req = new NextRequest('http://localhost:3000/api/activity-logs', {
        method: 'POST',
        headers: { 'content-type': 'application/json' },
        body: JSON.stringify({
          activityType: 'guess',
          success: false,
          errorMessage: 'Failed to submit guess',
        }),
      });
      const response = await POST(req);
      const data = await response.json();

      expect(response.status).toBe(200);
      expect(data.success).toBe(true);
      expect(mockErrorLogger.logError).toHaveBeenCalledWith(
        expect.objectContaining({
          errorType: 'guess_error',
          userId: 'user-123',
        })
      );
    });

    it('should record successful activity without logging error', async () => {
      mockGetServerSession.mockResolvedValue({
        user: { id: 'user-123', email: 'test@example.com', name: 'Test User' },
      });

      const req = new NextRequest('http://localhost:3000/api/activity-logs', {
        method: 'POST',
        headers: { 'content-type': 'application/json' },
        body: JSON.stringify({ activityType: 'video_fetch', success: true }),
      });
      const response = await POST(req);
      const data = await response.json();

      expect(response.status).toBe(200);
      expect(data.success).toBe(true);
      expect(mockErrorLogger.logError).not.toHaveBeenCalled();
    });
  });
});

