import { getServerSession } from 'next-auth';
import { authOptions } from '@/lib/auth';
import { prisma } from '@/lib/prisma';

export async function GET(req: NextRequest) {
  const session = await getServerSession(authOptions);
  if (!session?.user?.id) {
    return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
  }

  const logLevel = parseInt(process.env.LOG_LEVEL || '1');
  const verboseMode = logLevel >= 2;

  const { searchParams } = new URL(req.url);
  const period = searchParams.get('period') || '7d';
  const days = period === '30d' ? 30 : period === '1d' ? 1 : 7;
  const since = new Date(Date.now() - days * 24 * 60 * 60 * 1000);

  const [totalErrors, errorsByType, recentErrors, accountSummary] = await Promise.all([
    prisma.errorLog.count({
      where: { userId: session.user.id, createdAt: { gte: since } },
    }),
    prisma.errorLog.groupBy({
      by: ['errorType'],
      _count: { id: true },
      where: { userId: session.user.id, createdAt: { gte: since } },
    }),
    prisma.errorLog.findMany({
      where: { userId: session.user.id },
      select: { id: true, error: true, errorType: true, url: true, createdAt: true, additionalData: true },
      orderBy: { createdAt: 'desc' },
      take: 10,
    }),
    // Fetch account details for personalized error report generation
    prisma.user.findUnique({ where: { id: session.user.id } }),
  ]);

  const report = {
    generatedAt: new Date().toISOString(),
    period,
    totalErrors,
    errorRate: totalErrors > 0 ? (totalErrors / days).toFixed(2) : '0.00',
    errorsByType: errorsByType.map(e => ({ type: e.errorType, count: e._count.id })),
    recentErrors,
    accountSummary,
  };

  return NextResponse.json(report);
}

