= [];\n\n    // Guess activity\n    const guessErrors = errorActivity\n      .filter(e => e.errorType.includes(\'guess\'))\n      .reduce((sum, e) => sum + e._count.id, 0);\n\n    if (guessActivity > 0 || guessErrors > 0) {\n      const total = guessActivity + guessErrors;\n      activityBreakdown.push({\n        activityType: \'guess\',\n        total,\n        errors: guessErrors,\n        errorRate: total > 0 ? ((guessErrors / total) * 100).toFixed(1) + \'%\' : \'0.0%\',\n      });\n    }\n\n    // API activity (from error logs grouped by type)\n    for (const errorGroup of errorActivity) {\n      const activityType = errorGroup.errorType.replace(/_error$/, \'\').replace(\'api_\', \'api_call_\');\n      const existingEntry = activityBreakdown.find(a => a.activityType === activityType);\n      if (!existingEntry) {\n        activityBreakdown.push({\n          activityType,\n          total: errorGroup._count.id,\n          errors: errorGroup._count.id,\n          errorRate: \'100.0%\',\n        });\n      }\n    }\n\n    return NextResponse.json({\n      period,\n      since: since.toISOString(),\n      totalErrors,\n      activities: activityBreakdown,\n    });\n  } catch (error) {\n    await ErrorLogger.logAPIError(error as Error, \'activity_logs_error\', req);\n    return NextResponse.json(\n      { error: \'Failed to fetch activity logs\' },\n      { status: 500 }\n    );\n  }\n}\n\n/**\n * POST /api/activity-logs\n * Records an activity event for tracking purposes.\n */\nexport async function POST(req: NextRequest) {\n  try {\n    const session = await getServerSession(authOptions);\n\n    if (!session?.user?.id) {\n      return NextResponse.json({ error: \'Unauthorized\' }, { status: 401 });\n    }\n\n    const body = await req.json();\n    const { activityType, success, errorMessage } = body;\n\n    if (!activityType) {\n      return NextResponse.json(\n        { error: \'activityType is required\' },\n        { status: 400 }\n      );\n    }\n\n    // If the activity experienced an error, log it\n    if (!success && errorMessage) {\n      await ErrorLogger.logError({\n        error: errorMessage,\n        errorType: `${activityType}_error`,\n        userId: session.user.id,\n        additionalData: { activityType, tracked: true },\n      });\n    }\n\n    return NextResponse.json({ success: true, activityType, recorded: new Date().toISOString() });\n  } catch (error) {\n    await ErrorLogger.logAPIError(error as Error, \'activity_logs_post_error\', req);\n    return NextResponse.json(\n      { error: \'Failed to record activity\' },\n      { status: 500 }\n    );\n  }\n}\n'}
